    23→XPBlePollingService::XPBlePollingService(const string &vehicleTypeCode) {
    24→    this->vehicleTypeCode = vehicleTypeCode;
    25→}
    26→
    27→XPBlePollingService::~XPBlePollingService() {
    28→    INFO_LOG_WITH_LOCATION(this->logHelper, "pollingService deinit");
    29→    this->stopService();
    30→    // 释放回调
    31→    if (this->logHelper != nullptr) {
    32→        delete this->logHelper;
    33→        this->logHelper = nullptr;
    34→    }
    35→}
