    43→void XPBlePollingService::startService() {
    44→    INFO_LOG_WITH_LOCATION(this->logHelper, "pollingService start");
    45→    if (this->isStart) {
    46→        INFO_LOG_WITH_LOCATION(this->logHelper, "pollingService has start");
    47→        return;
    48→    }
    49→    if (logHelper == nullptr) {
    50→        INFO_LOG_WITH_LOCATION(this->logHelper, "logHelper is null");
    51→        return;
    52→    }
    53→    if (!this->isPollingSupport(vehicleTypeCode)) {
    54→        INFO_LOG_WITH_LOCATION(this->logHelper,  "vehicleTypeCode is not polling support: " + vehicleTypeCode);
    55→        return;
    56→    }
    57→    this->isStart = true;
    58→    // 启动服务
    59→    startBleLocationService();
    60→    startBlePollingService();
    61→    
    62→    // 使用weak_ptr避免循环引用
    63→    weak_ptr<XPBlePollingService> weak_this = shared_from_this();
    64→    gearValueListenId = this->vehicleState.drive.gearState.addListener([weak_this](const gear_state& gearState) {
    65→        if (auto strong_this = weak_this.lock()) {
    66→            strong_this->handleGearState(gearState);
    67→        }
    68→    });
    69→    
    70→    // 监听睡眠模式变化
    71→    sleepModeListenId = this->vehicleState.polling.sleepMode.addListener([weak_this](const sleep_mode& sleepMode) {
    72→        if (auto strong_this = weak_this.lock()) {
    73→            strong_this->handleSleepMode(sleepMode);
    74→        }
    75→    });
    76→    
    77→    // 监听轮询模式变化
    78→    pollingModeListenId = this->pollingConfig.pollingMode.addListener([weak_this](const polling_mode& pollingMode) {
    79→        if (auto strong_this = weak_this.lock()) {
    80→            strong_this->handlePollingMode(pollingMode);
    81→        }
    82→    });
    83→}
    84→
    85→void XPBlePollingService::stopService() {
    86→    INFO_LOG_WITH_LOCATION(this->logHelper, "blePollingService stop");
    87→    if (!this->isStart) {
    88→        INFO_LOG_WITH_LOCATION(this->logHelper, "blePollingService is not start");
    89→        return;
    90→    }
    91→    this->vehicleState.drive.gearState.removeListener(gearValueListenId);
    92→    this->vehicleState.polling.sleepMode.removeListener(sleepModeListenId);
    93→    this->pollingConfig.pollingMode.removeListener(pollingModeListenId);
    94→    // 停止服务
    95→    stopBleLocationService();
    96→    stopBlePollingService();
    97→    bleDisconnectClean();
    98→    this->isWatchLock = false;
    99→    this->isStart = false;
   100→}
