   195→void XPBlePollingService::bleConnectStateIsChanged(bool isConnected) {
   196→    const string connectedStr = isConnected ? "connected" : "disconnect";
   197→    INFO_LOG_WITH_LOCATION(this->logHelper, "bleConnectStateIsChanged: " + connectedStr);
   198→    if (this->bleIsConnected == isConnected) {
   199→        return;
   200→    }
   201→    this->bleIsConnected = isConnected;
   202→    if (!this->isStart) {
   203→        INFO_LOG_WITH_LOCATION(this->logHelper, "blePollingService is not start");
   204→        return;
   205→    }
   206→    auto now = time(nullptr);
   207→    if (isConnected) {
   208→        bleDisconnectClean();
   209→        if ((bleDisconnectTime == 0 || (bleDisconnectTime != 0 && difftime(now, bleDisconnectTime) > 7))) {
   210→            bleDisconnectTime = 0;
   211→            this->startBleLocationService();
   212→            this->startBlePollingService();
   213→        } else {
   214→            this->remuseBleLocationService();
   215→            this->remuseBlePollingService();
   216→        }
   217→    } else {
   218→        if (this->systemSwitch == false) {
   219→            bleDisconnectTime = 0;
   220→            bleDisconnectEventHandle = false;
   221→            if (this->blePollingManager != nullptr) {
   222→                this->blePollingManager->bleIsDisconnect();
   223→            }
   224→            this->stopBlePollingService();
   225→            this->stopBleLocationService();
   226→        } else {
   227→            this->startBleDisconnectRevert();
   228→        }
   229→    }
   230→}
