   318→void XPBlePollingService::requestBleLocationEvent() {
   319→    INFO_LOG_WITH_LOCATION(this->logHelper, "requestBleLocationEvent");
   320→    if (!this->isStart) {
   321→        INFO_LOG_WITH_LOCATION(this->logHelper, "blePollingService is not start");
   322→        return;
   323→    }
   324→    ble_location_version version = this->getCurrentBleLocationVersion();
   325→    if (version == ble_location_version_v1) {
   326→        if (result.distanceLevel <= ble_distance_level_unlock && result.distance != ble_distance_level_init) {
   327→            callback_->sendPollingAction(polling_action_in_car);
   328→        } else {
   329→            callback_->sendPollingAction(polling_action_out_car);
   330→        }
   331→    } else {
   332→        if (result.distance <= pollingConfig.startDistance && result.distance != POLLING_INVAILD_DISTANCE) {
   333→            callback_->sendPollingAction(polling_action_in_car);
   334→        } else {
   335→            callback_->sendPollingAction(polling_action_out_car);
   336→        }
   337→    }
   338→}
