   340→void XPBlePollingService::predictWithRssi(const string &rssiStr) {
   341→    if (!this->isStart) {
   342→        INFO_LOG_WITH_LOCATION(this->logHelper, "blePollingService is not start");
   343→        return;
   344→    }
   345→    if (this->bleLocationManager == nullptr) {
   346→        return;
   347→    }
   348→    if (this->serviceThread == nullptr) {
   349→        this->serviceThread = new XPThread();
   350→        this->serviceThread->start();
   351→    }
   352→    // 使用weak_ptr捕获this，避免循环引用
   353→    weak_ptr<XPBlePollingService> weak_this = shared_from_this();
   354→    // 将任务提交到常驻线程的任务队列
   355→    this->serviceThread->post([weak_this, rssiStr]() {
   356→        try {
   357→            auto strong_this = weak_this.lock();
   358→            if (!strong_this) {
   359→                return; // 对象已销毁，直接返回
   360→            }
   361→            ble_predict_result result;
   362→            ble_location_version version = strong_this->getCurrentBleLocationVersion();
   363→            strong_this->_predictWithRssi(rssiStr, version, result);
   364→            
   365→            if (result.error == ble_location_error_none) {
   366→                INFO_LOG_WITH_LOCATION(strong_this->logHelper, "predict result: " + bleLocationErrorToString(result.error) +
   367→                                        ", distance: " + to_string(result.distance) +
   368→                                        ", distanceLevel: " + bleDistanceLevelToString(result.distanceLevel) +
   369→                                       ", direction: " + vehicleDirectionToString(result.vehicleDirection));
   370→                strong_this->result = result;
   371→                
   372→                if (version == ble_location_version_v1) {
   373→                    if (result.distanceLevel >= ble_distance_level_lock) {
   374→                        strong_this->bleKeyIsFarAway();
   375→                    }
   376→                } else {
   377→                    if (result.distance > strong_this->pollingConfig.lockDistance) {
   378→                        strong_this->bleKeyIsFarAway();
   379→                    }
   380→                }
   381→                
   382→                if (strong_this->blePollingManager != nullptr) {
   383→                    strong_this->blePollingManager->decision((polling_distance_level)result.distanceLevel, result.distance, result.rssiStr);
   384→                }
   385→            }
   386→        } catch (const exception &e) {
   387→            auto strong_this = weak_this.lock();
   388→            if (strong_this && strong_this->logHelper) {
   389→                INFO_LOG_WITH_LOCATION(strong_this->logHelper, string("predictWithRssi exception: ") + e.what());
   390→            }
   391→        }
   392→    });
   393→    
   394→}
