   675→    } else {
   676→        vector<ble_direction_config_info_v4> threshod;
   677→        result =  XPBleLocationConfigParser::parseBleLoctionV4Config(this->bleLocationConfigJsonStr, this->vehicleTypeCode, this->finalHardware, threshod);
