    47→void XPBlePollingHandler::httpRevealLock() {
    48→    INFO_LOG_WITH_LOCATION(this->logHelper, "httpRevealLock");
    49→    if (pollingConfig->pollingMode != polling_mode_lock && pollingConfig->pollingMode != polling_mode_both) {
    50→        ERROR_LOG_WITH_LOCATION(this->logHelper, "polling mode not supported");
    51→        return;
    52→    }
    53→    if (vehicleState->door.doorLockState != door_lock_state_unlocked) {
    54→        ERROR_LOG_WITH_LOCATION(this->logHelper, "doorLockState is not unlocked");
    55→        return;
    56→    }
    57→    if (vehicleState->door.tempLockState == temp_lock_state_active) {
    58→        ERROR_LOG_WITH_LOCATION(this->logHelper, "tempLockState is active");
    59→        return;
    60→    }
    61→    if (vehicleState->seat.driverSeatOccupied == seat_occupied_active) {
    62→        ERROR_LOG_WITH_LOCATION(this->logHelper, "driverSeatOccupied is active");
    63→        return;
    64→    }
    65→    if (distanceLevel != polling_distance_level_init) {
    66→        if (distanceLevel <= polling_distance_level_enable) {
    67→            ERROR_LOG_WITH_LOCATION(this->logHelper, "distanceLevel in enable range");
    68→            return;
    69→        }
    70→    }
    71→    if (currentDistance != POLLING_INVAILD_DISTANCE) {
    72→        if (currentDistance <= pollingConfig->unlockDistance) {
    73→            ERROR_LOG_WITH_LOCATION(this->logHelper, "currentDistance in unlock range");
    74→            return;
    75→        }
    76→    }
    77→    
    78→    sendPollingAction(polling_action_http_lock);
    79→}
