    81→void XPBlePollingHandler::setIsFirstComming(bool isFirstComming) {
    82→    const string firstCommingStr = isFirstComming ? "YES" : "NO";
    83→    INFO_LOG_WITH_LOCATION(this->logHelper, "setIsFirstComming: " + firstCommingStr);
    84→    this->isFirstComming = isFirstComming;
    85→    if (isFirstComming) {
    86→        auto now = time(nullptr);
    87→        this->pollingStartTime = now;
    88→        this->pollingShield = false;
    89→    }
    90→}
