    92→polling_action_error_code XPBlePollingHandler::pollingUnlockIfNeed() {
    93→    if (this->pollingConfig->pollingMode != polling_mode_unlock && this->pollingConfig->pollingMode != polling_mode_both) {
    94→        return polling_action_error_code_mode_not_unlock;
    95→    }
    96→    if (this->vehicleState->door.doorLockState == door_lock_state_unlocked) {
    97→        return polling_action_error_code_door_not_lock;
    98→    }
    99→    if (this->vehicleState->door.tempLockState == temp_lock_state_active) {
   100→        return polling_action_error_code_temp_lock_active;
   101→    }
   102→    if (this->vehicleState->polling.alarmState == alarm_state_disarmed || this->vehicleState->polling.alarmState == alarm_state_remind || this->vehicleState->polling.alarmState == alarm_state_alarm) {
   103→        return polling_action_error_code_alarm_state_error;
   104→    }
   105→    if (this->pollingUnlockTryCount >= 3) {
   106→        return polling_action_error_code_try_count_limit;
   107→    }
   108→    auto now = time(nullptr);
   109→    if (this->unlockOperateTime != 0) {
   110→        float interval = difftime(now, this->unlockOperateTime);
   111→        if (interval < 6) {
   112→            return polling_action_error_code_event_interval_limit;
   113→        }
   114→    }
   115→    if (this->prevUnlockCommandTime != 0) {
   116→        float interval = difftime(now, this->prevUnlockCommandTime);
   117→        if (interval < pollingUnlockInterval) {
   118→            return polling_action_error_code_command_interval_limit;
   119→        }
   120→    }
   121→    this->prevUnlockCommandTime = now;
   122→    this->pollingUnlockTryCount += 1;
   123→    return polling_action_error_code_none;
