   126→polling_action_error_code XPBlePollingHandler::pollingLockIfNeed() {
   127→    if (this->pollingConfig->pollingMode != polling_mode_lock && this->pollingConfig->pollingMode != polling_mode_both) {
   128→       return polling_action_error_code_mode_not_lock;
   129→    }
   130→    if (this->vehicleState->door.doorLockState != door_lock_state_unlocked) {
   131→        return polling_action_error_code_door_not_unlock;
   132→    }
   133→    if (isDoorOpen == true) {
   134→        return polling_action_error_code_door_open;
   135→    }
   136→    if (this->pollingLockTryCount >= 3) {
   137→        return polling_action_error_code_try_count_limit;
   138→    }
   139→    auto now = time(nullptr);
   140→    if (this->lockOperateTime != 0) {
   141→        float interval = difftime(now, this->lockOperateTime);
   142→        if (interval < 6) {
   143→            return polling_action_error_code_event_interval_limit;
   144→        }
   145→    }
   146→    if (this->prevLockCommandTime != 0) {
   147→        float interval = difftime(now, this->prevLockCommandTime);
   148→        if (interval < pollingLockInterval) {
   149→            return polling_action_error_code_command_interval_limit;
   150→        }
   151→    }
   152→    this->prevLockCommandTime = now;
   153→    this->pollingLockTryCount += 1;
   154→    return polling_action_error_code_none;
   155→}
