   202→void XPBlePollingHandler::setupListener() {
   203→    weak_ptr<XPBlePollingHandler> weak_this = shared_from_this();
   204→    doorLockListenId = this->vehicleState->door.doorLockState.addListener([weak_this](const door_lock_state& doorLockState) {
   205→        if (auto strong_this = weak_this.lock()) {
   206→            if (strong_this->currentDoorLockState != door_lock_state_default && strong_this->currentDoorLockState != doorLockState) {
   207→                
   208→                if (strong_this->currentDoorLockState == door_lock_state_locked && doorLockState == door_lock_state_unlocked) {
   209→                    strong_this->currentDoorLockState = doorLockState;
   210→                    strong_this->detectCarIsUnlocked();
   211→                } else if (strong_this->currentDoorLockState == door_lock_state_unlocked && doorLockState == door_lock_state_locked) {
   212→                    strong_this->currentDoorLockState = doorLockState;
   213→                    strong_this->detectCarIsLocked();
   214→                } else {
   215→                    strong_this->currentDoorLockState = doorLockState;
   216→                }
   217→            } else {
   218→                strong_this->currentDoorLockState = doorLockState;
   219→            }
   220→        }
   221→    });
   222→    driverDoorListenId = this->vehicleState->door.driverDoorAjarState.addListener([weak_this](const door_ajar_state& doorAjarState) {
   223→        if (auto strong_this = weak_this.lock()) {
   224→            strong_this->handleDoorState();
   225→        }
   226→    });
   227→    passengerDoorListenId = this->vehicleState->door.passengerDoorAjarState.addListener([weak_this](const door_ajar_state& doorAjarState) {
   228→        if (auto strong_this = weak_this.lock()) {
   229→            strong_this->handleDoorState();
   230→        }
   231→    });
   232→    rlDoorListenId = this->vehicleState->door.rearLeftDoorAjarState.addListener([weak_this](const door_ajar_state& doorAjarState) {
   233→        if (auto strong_this = weak_this.lock()) {
   234→            strong_this->handleDoorState();
   235→        }
   236→    });
   237→    rrDoorListenId = this->vehicleState->door.rearRightDoorAjarState.addListener([weak_this](const door_ajar_state& doorAjarState) {
   238→        if (auto strong_this = weak_this.lock()) {
   239→            strong_this->handleDoorState();
   240→        }
   241→    });
   242→    trunkListenId = this->vehicleState->door.trunkAjarState.addListener([weak_this](const trunk_ajar_state& doorAjarState) {
   243→        if (auto strong_this = weak_this.lock()) {
   244→            strong_this->handleDoorState();
   245→        }
   246→    });
   247→    bonnetListenId = this->vehicleState->door.bonnetAjarState.addListener([weak_this](const bonnet_ajar_state& doorAjarState) {
   248→        if (auto strong_this = weak_this.lock()) {
   249→            strong_this->handleDoorState();
   250→        }
   251→    });
   252→}
