   256→    this->vehicleState->door.doorLockState.removeListener(doorLockListenId);
   257→    this->vehicleState->door.driverDoorAjarState.removeListener(driverDoorListenId);
   258→    this->vehicleState->door.passengerDoorAjarState.removeListener(passengerDoorListenId);
