   332→void XPBlePollingHandler::handleDoorState() {
   333→    INFO_LOG_WITH_LOCATION(this->logHelper, "handleDoorState");
   334→    if (vehicleState->door.driverDoorAjarState == door_ajar_state_open || vehicleState->door.passengerDoorAjarState == door_ajar_state_open || vehicleState->door.rearLeftDoorAjarState == door_ajar_state_open || vehicleState->door.rearRightDoorAjarState == door_ajar_state_open || vehicleState->door.trunkAjarState > trunk_ajar_state_close || vehicleState->door.bonnetAjarState > bonnet_ajar_state_close) {
   335→        detectCarDoorIsOpen();
   336→    } else {
   337→        if (isDoorOpen == true) {
   338→            detectCarDoorHadOpen();
   339→        }
   340→        isDoorOpen = false;
   341→    }
   342→}
