    56→void XPBlePollingHandlerV1::predictDoorLockAction() {
    57→    if (distanceLevel == polling_distance_level_incar && this->lastDistanceLevel < polling_distance_level_unlock) {
    58→        pollingInCar();
    59→        return;
    60→    }
    61→    polling_distance_level unlockCompareLevel = polling_distance_level_unlock;
    62→    if (this->pollingConfig->isConvenient) {
    63→        unlockCompareLevel = polling_distance_level_enable;
    64→    }
    65→    if (distanceLevel <= unlockCompareLevel) {
    66→        if (lastDistanceLevel > polling_distance_level_incar || lastDistanceLevel == polling_distance_level_init) {
    67→            pollingUnlock();
    68→        } else {
    69→            pollingInCar();
    70→        }
    71→    } else {
    72→        if (distanceLevel >= polling_distance_level_lock) {
    73→            pollingLock();
    74→        }
    75→    }
    76→}
