    78→void XPBlePollingHandlerV1::predictTrunkLockAction() {
    79→    if (distanceLevel < polling_distance_level_lock && (lastDistanceLevel >= polling_distance_level_lock || lastDistanceLevel == polling_distance_level_init)) {
    80→        pollingTrunkEnable();
    81→    } else if (distanceLevel > polling_distance_level_lock && lastDistanceLevel <= polling_distance_level_lock && lastDistanceLevel != polling_distance_level_init) {
    82→        pollingTrunkDisable();
    83→    }
    84→}
