    15→json_parse_result XPBlePollingConfigParser::parsePollingConfig(const string &jsonStr, POLLING_SERVICE::polling_config &pollingConfig) {
    16→    try {
    17→        json remotePollingConfig = json::parse(jsonStr);
    18→        if (!remotePollingConfig.is_object()) {
    19→            throw logic_error("failed");
    20→        }
    21→        if (remotePollingConfig.contains("isWelcome")) {
    22→            pollingConfig.isWelocme = remotePollingConfig["isWelcome"];
    23→        }
    24→        if (remotePollingConfig.contains("isConvenient")) {
    25→            pollingConfig.isConvenient = remotePollingConfig["isConvenient"];
    26→        }
    27→        if (remotePollingConfig.contains("unlockDistance")) {
    28→            pollingConfig.unlockDistance = remotePollingConfig["unlockDistance"];
    29→        }
    30→        if (remotePollingConfig.contains("lockDistance")) {
    31→            pollingConfig.lockDistance = remotePollingConfig["lockDistance"];
    32→        }
    33→        if (remotePollingConfig.contains("startDistance")) {
    34→            pollingConfig.startDistance = remotePollingConfig["startDistance"];
    35→        }
    36→        if (remotePollingConfig.contains("enableDistance")) {
    37→            pollingConfig.enableDistance = remotePollingConfig["enableDistance"];
    38→        }
    39→        if (remotePollingConfig.contains("lockHoldOnSecond")) {
    40→            pollingConfig.lockHoldOnSecond = remotePollingConfig["lockHoldOnSecond"];
    41→        }
    42→        if (remotePollingConfig.contains("pollingMode")) {
    43→            pollingConfig.pollingMode = remotePollingConfig["pollingMode"];
    44→        }
    45→        if (remotePollingConfig.contains("selfCalibrationTxPowerV2")) {
    46→            const auto &txPowerArray = remotePollingConfig["selfCalibrationTxPowerV2"];
    47→            for (const auto& element : txPowerArray) {
    48→                self_calibration_model selfCalibrationMode;
    49→                selfCalibrationMode.direction = element["direction"];
    50→                const auto &rssiArray = element["txPowerArray"];
    51→                for (const auto& it : rssiArray) {
    52→                    ble_rssi rssi;
    53→                    rssi.postion = it["name"];
    54→                    rssi.rssi = it["txPower"];
    55→                    selfCalibrationMode.txPowerArray.push_back(rssi);
    56→                }
    57→                pollingConfig.selfCalibrationData.push_back(selfCalibrationMode);
    58→            }
    59→        }
    60→    } catch (const exception &e) {
    61→        return json_parse_result_failed;
    62→    }
    63→    return json_parse_result_success;
    64→}
