   465→json_parse_result XPBleLocationConfigParser::loadDefaultBleLoctionV4Config(const string &vehicleTypeCode, const string &hardware, vector<ble_direction_config_info_v4> &bleDirectionConfigInfos) {
   466→    try {
   467→        string vehicleName = vehicleCodeMapName.at(vehicleTypeCode);
   468→        if (pollingV2ThresholdMap.find(vehicleName) == pollingV2ThresholdMap.end()) {
   469→            throw logic_error("no key");
   470→        }
   471→        if (coverScaleMap.find(vehicleName) == coverScaleMap.end()) {
   472→            throw logic_error("no key");
   473→        }
   474→        json vehicleConfig = json::parse(pollingV2ThresholdMap.at(vehicleName));
   475→        const auto &pollingDirectionConfig = vehicleConfig["directionConfig"];
   476→        if (!pollingDirectionConfig.contains(hardware)) {
   477→            throw logic_error("no hardware");
   478→        }
   479→        json directionCoverMapConfig = json::parse(coverScaleMap.at(vehicleName));
   480→        const auto &hardwareConfig = pollingDirectionConfig[hardware];
   481→        for (auto it = hardwareConfig.begin(); it != hardwareConfig.end(); ++it) {
   482→            ble_direction_config_info_v4 bleDirectionConfigInfo;
   483→            string directionKey = it.key();
   484→            vehicle_direction direction = directionKeyMapDirection.at(directionKey);
   485→            bleDirectionConfigInfo.direction = direction;
   486→            
   487→            const auto &directionConfig = it.value();
   488→            for (auto sub = directionConfig.begin(); sub != directionConfig.end(); ++sub) {
   489→                ble_config_info bleConfigInfo;
   490→                string bleName = sub.key();
   491→                const auto &bleConfig = sub.value();
   492→                ble_postion blePosition = bleNameMapPosition.at(bleName);
   493→                bleConfigInfo.txPower = bleConfig["txPower"];
   494→                bleConfigInfo.a = bleConfig["a"];
   495→                bleConfigInfo.b = bleConfig["b"];
   496→                bleConfigInfo.c = bleConfig["c"];
   497→                bleConfigInfo.postion = blePosition;
   498→                bleConfigInfo.is_communicate = blePosition == ble_postion_center;
   499→                bleDirectionConfigInfo.bleConfigs.push_back(bleConfigInfo);
   500→            }
   501→            
   502→            const auto &coverMapConfig = directionCoverMapConfig[directionKey];
   503→            for (const auto& element : coverMapConfig) {
   504→                ble_cover_map coverMap;
   505→                coverMap.postion = bleNameMapPosition.at(element["name"]);
   506→                coverMap.lessScale = element["lessScale"];
   507→                coverMap.moreScale = element["moreScale"];
   508→                coverMap.isWeightPriority = (bool)element["isWeightPriority"].get<int>();
   509→                bleDirectionConfigInfo.coverMap.push_back(coverMap);
   510→            }
   511→            bleDirectionConfigInfos.push_back(bleDirectionConfigInfo);
   512→        }
   513→    } catch (const exception &e) {
   514→        if (strstr(e.what(), "no hardware")) {
   515→            return json_parse_result_nokey;
   516→        }
   517→        if (strstr(e.what(), "no key")) {
   518→            return json_parse_result_nokey;
   519→        }
   520→        return json_parse_result_failed;
   521→    }
   522→    return json_parse_result_default_value;
   523→}
