     8→#ifndef Timer_h
     9→#define Timer_h
    10→
    11→#include <thread>
    12→#include <mutex>
    13→#include <condition_variable>
    14→#include <atomic>
    15→
    16→namespace XPBase {
    17→
    18→class Timer {
    19→public:
    20→    Timer() = default;
    21→    ~Timer() { stop(); }
    22→    
    23→    // 禁用拷贝
    24→    Timer(const Timer&) = delete;
    25→    Timer& operator=(const Timer&) = delete;
    26→    
    27→    void start(int interval_ms, std::function<void()> callback,  bool fireImmediately = true) {
    28→        stop();
    29→        running = true;
    30→        worker = std::thread([this, interval_ms, callback, fireImmediately] {
    31→            // 首次立即执行
    32→            if (fireImmediately) {
    33→                try {
    34→                    callback();
    35→                } catch (...) {
    36→                }
    37→            }
    38→            // 周期性执行
    39→            auto next_run = std::chrono::steady_clock::now() +
    40→            std::chrono::milliseconds(interval_ms);
    41→            while (running) {
    42→                std::unique_lock<std::mutex> lock(mtx);
    43→                if (cv.wait_until(lock, next_run, [this] { return !running; })) {
    44→                    break;
    45→                }
    46→                callback();
    47→                next_run += std::chrono::milliseconds(interval_ms);
    48→            }
    49→        });
    50→    }
    51→    
    52→    void stop() {
    53→        running = false;
    54→        cv.notify_all();
    55→        if (worker.joinable()) {
    56→            if (std::this_thread::get_id() != worker.get_id()) {
    57→                worker.join();
    58→            } else {
    59→                worker.detach();
    60→            }
    61→        }
    62→    }
    63→    
    64→private:
    65→    std::thread worker;
    66→    std::mutex mtx;
    67→    std::condition_variable cv;
    68→    std::atomic<bool> running{false};
    69→};
    70→
    71→}
    72→
    73→
    74→#endif /* Timer_h */
    75→

