    50→void XPPredictModelV1::predictWithRssi(vector<XPRssiModel> rssiArray, ble_predict_result &locationResult) {
    51→    if (model == NULL) {
    52→        locationResult.error = ble_location_error_no_model;
    53→        return;
    54→    }
    55→    if (rssiArray.empty()) {
    56→        locationResult.error = ble_location_error_no_rssi_data;
    57→        return;
    58→    }
    59→    auto last = rssiArray.front();
    60→    if (last.rssi >= 0) {
    61→        locationResult.error = ble_location_error_input_invaild;
    62→        return;
    63→    }
    64→    auto position = ecuNameMapPosition.at(last.name);
    65→    vector<short> rssiV;
    66→    if (position == ble_postion_center) {
    67→        rssiV.push_back(last.rssi);
    68→        rssiV.push_back(0);
    69→        rssiV.push_back(0);
    70→        rssiV.push_back(0);
    71→    } else if (position == ble_postion_left_front) {
    72→        rssiV.push_back(0);
    73→        rssiV.push_back(last.rssi);
    74→        rssiV.push_back(0);
    75→        rssiV.push_back(0);
    76→    }  else if (position == ble_postion_right_front) {
    77→        rssiV.push_back(0);
    78→        rssiV.push_back(0);
    79→        rssiV.push_back(0);
    80→        rssiV.push_back(last.rssi);
    81→    } else if (position == ble_postion_rear){
    82→        rssiV.push_back(0);
    83→        rssiV.push_back(0);
    84→        rssiV.push_back(last.rssi);
    85→        rssiV.push_back(0);
    86→    }
    87→    vector<vector<short>> input;
    88→    XPPredictInferenceV1 *interfaceModel = (XPPredictInferenceV1 *)model;
    89→    interfaceModel->preprocess(rssiV, input);
    90→    if (input.empty()) {
    91→        locationResult.error = ble_location_error_input_null;
    92→        return;
    93→    }
    94→    std::vector<float> output;
    95→    interfaceModel->inference(output, locationResult.rssiStr);
    96→    if (output.empty() || output.size() == 0) {
    97→        locationResult.error = ble_location_error_predict_failed;
    98→        return;
    99→    }
   100→    if (output.size() == 2) {
   101→        float distance = output[0];
   102→        short trendResult = output[1];
   103→        ble_distance_level distanceLevel = (ble_distance_level)(distance + 0.5);
   104→        if (distanceLevel == ble_distance_level_incar) {
   105→            if (this->inCarPower < IN_CAR_POWER_COUNT) {
   106→                this->inCarPower += 1;
   107→            }
   108→        } else {
   109→            if (this->inCarPower > 0) {
   110→                this->inCarPower -= 1;
   111→                distanceLevel = ble_distance_level_incar;
   112→            } else {
   113→                this->inCarPower = 0;
   114→            }
   115→        }
   116→        if (distanceLevel < ble_distance_level_welcome && distanceLevel > ble_distance_level_unlock
   117→            && this->bussinessDistance.isConvenient == true && trendResult == 0) {
   118→            this->distanceLevel = ble_distance_level_unlock;
   119→        }
   120→        this->distanceLevel = distanceLevel;
   121→        locationResult.distanceLevel = distanceLevel;
   122→        locationResult.error = ble_location_error_none;
   123→    }
   124→}
   125→
   126→}
