     8→#ifndef XPThread_hpp
     9→#define XPThread_hpp
    10→
    11→#include <thread>
    12→#include <queue>
    13→#include <mutex>
    14→#include <condition_variable>
    15→#include <functional>
    16→#include <atomic>
    17→
    18→namespace POLLING_SERVICE {
    19→
    20→/**
    21→ * 常驻工作线程，用于处理异步任务
    22→ */
    23→class XPThread {
    24→public:
    25→    using Task = std::function<void()>;
    26→    
    27→    XPThread() : running(false) {}
    28→    
    29→    ~XPThread() {
    30→        stop();
    31→    }
    32→    
    33→    /**
    34→     * 启动工作线程
    35→     */
    36→    void start() {
    37→        if (running) {
    38→            return;
    39→        }
    40→        running = true;
    41→        worker = std::thread(&XPThread::run, this);
    42→    }
    43→    
    44→    /**
    45→     * 停止工作线程
    46→     */
    47→    void stop() {
    48→        if (!running) {
    49→            return;
    50→        }
    51→        running = false;
    52→        cv.notify_all();
    53→        
    54→        if (worker.joinable()) {
    55→            // 避免死锁：检查当前线程是否是工作线程
    56→            if (std::this_thread::get_id() != worker.get_id()) {
    57→                worker.join();
    58→            } else {
    59→                worker.detach();
    60→            }
    61→        }
    62→    }
    63→    
    64→    /**
    65→     * 提交任务到工作线程
    66→     */
    67→    void post(Task task) {
    68→        if (!running) {
    69→            return;
    70→        }
    71→        {
    72→            std::lock_guard<std::mutex> lock(mutex);
    73→            tasks.push(std::move(task));
    74→        }
    75→        cv.notify_one();
    76→    }
    77→    
    78→    /**
    79→     * 判断线程是否正在运行
    80→     */
    81→    bool isRunning() const {
    82→        return running;
    83→    }
    84→    
    85→private:
    86→    /**
    87→     * 工作线程主循环
    88→     */
    89→    void run() {
    90→        while (running) {
    91→            Task task;
    92→            {
    93→                std::unique_lock<std::mutex> lock(mutex);
    94→                cv.wait(lock, [this] { return !tasks.empty() || !running; });
    95→                
    96→                if (!running && tasks.empty()) {
    97→                    break;
    98→                }
    99→                
   100→                if (!tasks.empty()) {
   101→                    task = std::move(tasks.front());
   102→                    tasks.pop();
   103→                }
   104→            }
   105→            
   106→            if (task) {
   107→                try {
   108→                    task();
   109→                } catch (...) {
   110→                    // 捕获所有异常，防止线程崩溃
   111→                }
   112→            }
   113→        }
   114→    }
   115→    
   116→    std::thread worker;
   117→    std::queue<Task> tasks;
   118→    std::mutex mutex;
   119→    std::condition_variable cv;
   120→    std::atomic<bool> running;
   121→};
   122→
   123→}
   124→
   125→#endif /* XPThread_hpp */
