    31→float XPPredictInferenceV1::lsqe(const vector<short> &x, const vector<short> &y) {
    32→    if (x.size() != y.size() || x.size() == 0) {
    33→        return 0;
    34→    }
    35→    
    36→    float t1 = 0, t2 = 0, t3 = 0, t4 = 0;
    37→    for (int i = 0; i < x.size(); ++i) {
    38→        t1 += x[i] * x[i];
    39→        t2 += x[i];
    40→        t3 += x[i] * y[i];
    41→        t4 += y[i];
    42→    }
    43→    float k = (t3 * x.size() - t2 * t4) / (t1 * x.size() - t2 * t2);  // 求得β1
    44→    return k;
    45→}
