    47→void XPPredictInferenceV1::preprocess(const vector<short> &rssi, vector<vector<short>> &output) {
    48→    output.clear();
    49→    
    50→    while(singleRSSIWindow.size() > RSSI_LENGTH * 2){
    51→        singleRSSIWindow.pop_front();
    52→    }
    53→    if(rssi.size() == 0){
    54→        return;
    55→    }
    56→    
    57→    //输入的不是主蓝牙信号，推入后返回
    58→    if(rssi[0] == 0){
    59→        singleRSSIWindow.push_back(rssi);
    60→        return;
    61→    }
    62→    
    63→    //输入的是主蓝牙信号
    64→    //读取资料，并检查各位置数值
    65→    set<short> rssiPosition;
    66→    vector<short> fullRSSI(RSSI_LENGTH, 0);
    67→    for(const auto &singleRSSI : singleRSSIWindow){
    68→        for(int i=0; i<RSSI_LENGTH; i++){
    69→            if(singleRSSI[i] != 0 && !isnan(singleRSSI[i])){
    70→                rssiPosition.insert(i);
    71→                fullRSSI[i] = singleRSSI[i];
    72→                break;
    73→            }
    74→        }
    75→    }
    76→    string sizeLog = "AKModel, Size:" + to_string(rssiPosition.size());
    77→    predictLog(sizeLog);
    78→    //清空当前窗口，并推入下个窗口的主蓝牙值
    79→    singleRSSIWindow.clear();
    80→    singleRSSIWindow.push_back(rssi);
    81→    
    82→    //主蓝牙缺值，返回
    83→    if(fullRSSI[0] == 0){
    84→        return;
    85→    }
    86→    
    87→    //少于三个位置的资料
    88→    string log = "";
    89→    if(rssiPosition.size() < RSSI_LENGTH - 1){
    90→        if (fullRSSIWindow.size() == 0) {
    91→            bool needWait = true;
    92→            for(int i = 0; i < fullRSSI.size(); i++){
    93→                if ((fullRSSI[i] != 0 && !isnan(fullRSSI[i])) && fullRSSI[i] > twoMeterRSSI[i]) {
    94→                    needWait = false;
    95→                    break;
    96→                }
    97→            }
    98→            if (needWait) {
    99→                if(rssiFailCount < 3){
   100→                    log = "window size < 3,and is not in 4m，need wait";
   101→                    rssiFailCount += 1;
   102→                    predictLog(log);
   103→                    return;
   104→                } else {
   105→                    log = "window size >= 3, predict";
   106→                    predictLog(log);
   107→                }
   108→            } else {
   109→                log = "in 4m, predict";
   110→                predictLog(log);
   111→            }
   112→        } else {
   113→            log = "window size > 0, predict";
   114→            predictLog(log);
   115→        }
   116→    } else{
   117→        rssiFailCount = 0;
   118→    }
   119→    
   120→    //补缺值
   121→    for (int i=0; i<RSSI_LENGTH; i++) {
   122→        if(fullRSSI[i] == 0){
   123→            fullRSSI[i] = DISCONNECT_RSSI;
   124→        }
   125→    }
   126→    
   127→    //推入窗口，之后的步骤使用窗口内资料计算
   128→    fullRSSIWindow.push_back(fullRSSI);
   129→    if(fullRSSIWindow.size() < FULL_RSSI_WINDOW_MIN_SIZE){
   130→        return;
   131→    }
   132→    while(fullRSSIWindow.size() > FULL_RSSI_WINDOW_MAX_SIZE){
   133→        fullRSSIWindow.pop_front();
   134→    }
   135→    //象征性输出资料，以维持兼容
   136→    for(const auto &value : unlockRSSI){
   137→        fullRSSI.push_back(value);
   138→    }
   139→    output.push_back(fullRSSI);
   140→}
