   142→void XPPredictInferenceV1::inference(vector<float> &output, string &rssiStr) {
   143→    output.clear();
   144→    string log = "";
   145→    vector<short> fullRSSI;
   146→    if (fullRSSIWindow.size() == 0) {
   147→        log = "AKModel, fullRSSIWindow size = 0";
   148→        predictLog(log);
   149→        return;
   150→    } else {
   151→        fullRSSI = fullRSSIWindow.back();
   152→    }
   153→    if (fullRSSI.size() == 0) {
   154→        log = "可能存在多线程清fullRssiWindow导致崩溃的风险，所以添加容错保护";
   155→        predictLog(log);
   156→        return;
   157→    }
   158→    float newDistanceLevel = 0;
   159→    float trendResult = 1;
   160→    auto oneMeterCircle = oneMeterRSSI;
   161→    auto twoMeterCircle = twoMeterRSSI;
   162→    auto sixMeterCircle = sixMeterRSSI;
   163→    auto tenMeterCircle = tenMeterRSSI;
   164→    
   165→    if (oneMeterCircle.size() < RSSI_LENGTH || twoMeterCircle.size() < RSSI_LENGTH || sixMeterCircle.size() < RSSI_LENGTH || tenMeterCircle.size() < RSSI_LENGTH) {
   166→        log = "AKModel, 任何一个阈值数据都不能小于4";
   167→        predictLog(log);
   168→        return;
   169→    }
   170→    
   171→    if (fullRSSI[0] > -50) {
   172→        currentDistanceLevel = 0;
   173→        log = "AKModel, 信号过强，直接认为在车内";
   174→        predictLog(log);
   175→        output.push_back(currentDistanceLevel);
   176→        output.push_back(trendResult);
   177→        return;
   178→    }
   179→    
   180→    short totalCount = 0;
   181→    short moreThanOneMeterCount = 0;
   182→    short moreThanTwoMeterCount = 0;
   183→    short moreThanSixMeterCount = 0;
   184→    short moreThanTenMeterCount = 0;
   185→    short lessThanTenMeterCount = 0;
   186→    
   187→    for(int i=0; i<RSSI_LENGTH; i++){
   188→        if(fullRSSI[i] != DISCONNECT_RSSI){
   189→            totalCount++;
   190→            if(fullRSSI[i] > oneMeterCircle[i])  moreThanOneMeterCount++;
   191→            if(fullRSSI[i] > twoMeterCircle[i])  moreThanTwoMeterCount++;
   192→            if(fullRSSI[i] > sixMeterCircle[i])  moreThanSixMeterCount++;
   193→            if(fullRSSI[i] >= tenMeterCircle[i]) moreThanTenMeterCount++;
   194→            if(fullRSSI[i] < tenMeterCircle[i])  lessThanTenMeterCount++;
   195→        }
   196→    }
   197→    log = "计算的结果totalCount:" + to_string(totalCount) + "moreThanOneMeterCount:" + to_string(moreThanOneMeterCount) + "moreThanTwoMeterCount:" + to_string(moreThanTwoMeterCount) + "moreThanSixMeterCount" +
   198→    to_string(moreThanSixMeterCount) +  "moreThanTenMeterCount" + to_string(lessThanTenMeterCount);
   199→    predictLog(log);
   200→    
   201→    // 匹配规则
   202→    switch (totalCount) {
   203→            
   204→        case 1:
   205→        {
   206→            if(moreThanOneMeterCount >= 1) {
   207→                newDistanceLevel = 1;
   208→            } else if(moreThanTwoMeterCount == 1) {
   209→                if (this->bleType == CurrentBleType_KW36MAIN) {
   210→                    newDistanceLevel = 2;
   211→                } else {
   212→                    newDistanceLevel = 3;
   213→                }
   214→            } else if(lessThanTenMeterCount == 1) {
   215→                newDistanceLevel = 5;
   216→            } else {
   217→                newDistanceLevel = 4;
   218→            }
   219→        }
   220→            break;
   221→        case 2:
   222→        case 3:
   223→        case 4:
   224→        {
   225→            if (moreThanOneMeterCount >= 1) {
   226→                newDistanceLevel = 1;
   227→            } else if(moreThanTwoMeterCount >= 2) {
   228→                if (this->bleType == CurrentBleType_CC2640) {
   229→                    newDistanceLevel = 2;
   230→                } else {
   231→                    newDistanceLevel = 1;
   232→                }
   233→            } else if(moreThanTwoMeterCount == 1 && moreThanSixMeterCount >= 2) {
   234→                if (moreThanSixMeterCount >= 3) {
   235→                    newDistanceLevel = 2;
   236→                } else {
   237→                    if (this->bleType == CurrentBleType_CC2640) {
   238→                        newDistanceLevel = 3;
   239→                    } else {
   240→                        newDistanceLevel = 2;
   241→                    }
   242→                }
   243→            } else if(moreThanTwoMeterCount == 1) {
   244→                if (this->bleType == CurrentBleType_KW36MAIN) {
   245→                    newDistanceLevel = 2;
   246→                } else {
   247→                    newDistanceLevel = 3;
   248→                }
   249→            } else if(moreThanSixMeterCount >= 2) {
   250→                newDistanceLevel = 3;
   251→            } else if (lessThanTenMeterCount >= totalCount) {
   252→                newDistanceLevel = 6;
   253→            } else if (moreThanSixMeterCount == 0 && lessThanTenMeterCount >= totalCount - 1) {
   254→                newDistanceLevel = 5;
   255→            } else {
   256→                newDistanceLevel = 4;
   257→            }
   258→        }
   259→            
   260→        default:
   261→            break;
   262→    }
   263→    if (currentDistanceLevel == -1) {
   264→        currentDistanceLevel = newDistanceLevel;
   265→    } else {
   266→        if (newDistanceLevel > currentDistanceLevel) {
   267→            currentDistanceLevel = (1-LOCK_DISTANCE_ALPHA) * currentDistanceLevel + LOCK_DISTANCE_ALPHA * newDistanceLevel;
   268→        } else {
   269→            currentDistanceLevel = (1-UNLOCK_DISTANCE_ALPHA) * currentDistanceLevel + UNLOCK_DISTANCE_ALPHA * newDistanceLevel;
   270→        }
   271→    }
   272→    log = "AKModel, 计算的距离是:" + to_string(newDistanceLevel) + "更新的距离是:" + to_string(currentDistanceLevel);
   273→    
   274→    output.push_back(currentDistanceLevel);
   275→    
   276→    rssiStr = dequeVectorInput(fullRSSIWindow);
   277→    if (this->bleType == CurrentBleType_KW36MAIN) {
   278→        //趋势逻辑
   279→        if(fullRSSIWindow.size() > FULL_RSSI_WINDOW_MAX_SIZE - 1){
   280→            short positiveCount = 0;
   281→            float maxPositiveK = 0;
   282→            
   283→            vector<short> kVector;
   284→            auto rssiWindow = fullRSSIWindow;
   285→            for (int i = 0; i < RSSI_LENGTH; i++) {
   286→                vector<short> x;
   287→                vector<short> y;
   288→                for(int j = 0; j < rssiWindow.size(); j++){
   289→                    if (rssiWindow[j][i] != DISCONNECT_RSSI) {
   290→                        x.push_back(j);
   291→                        y.push_back(rssiWindow[j][i]);
   292→                    }
   293→                }
   294→                float k = lsqe(x, y);
   295→                // 处理窗口数据过小时斜率过大的问题
   296→                k = k * ((float)x.size()/FULL_RSSI_WINDOW_MAX_SIZE);
   297→                kVector.push_back(k);
   298→                if(k > maxPositiveK) {
   299→                    maxPositiveK = k;
   300→                }
   301→                if (k >= 1.0 ) {
   302→                    positiveCount += 1;
   303→                }
   304→                log = "AKModel, RSSI index:" + to_string(i) + ":" + printFloatVector(kVector);
   305→                predictLog(log);
   306→            }
   307→            
   308→            if(maxPositiveK >= 1.5 || positiveCount >= 2){
   309→                trendResult = 0;
   310→                log = "AKModel, 靠近趋势";
   311→                predictLog(log);
   312→            }
   313→        }
   314→        output.push_back(trendResult);
   315→    } else {
   316→        output.push_back(trendResult);
   317→    }
   318→}
   319→
   320→}
